# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, send_file
from apscheduler.schedulers.background import BackgroundScheduler
import subprocess
import boto3
import io

app = Flask(__name__)
s3 = boto3.client('s3')

def take_screenshot(url):
    process = subprocess.Popen(['chromium-browser', '--headless', '--disable-gpu', '--no-sandbox', '--disable-dev-shm-usage', f'--url={url}', '--print-to-pdf=screenshot.pdf'], stdout=subprocess.PIPE)
    output, _ = process.communicate()

    with open('screenshot.pdf', 'rb') as f:
        s3.upload_fileobj(f, 'screenshots', url.split('/')[-1] + '.png')
        s3.meta.client.head_object(Bucket='screenshots', Key=url.split('/')[-1] + '.png')
        s3.generate_presigned_url('get_object', Params={'Bucket': 'screenshots', 'Key': url.split('/')[-1] + '.png'}, ExpiresIn=3600)

@app.route('/screenshot', methods=['POST'])
def screenshot():
    if request.method == 'POST':
        url = request.form['url']
        take_screenshot(url)
        return send_file(io.BytesIO(s3.generate_presigned_url('get_object', Params={'Bucket': 'screenshots', 'Key': url.split('/')[-1] + '.png'})['Url']), mimetype='image/png')

if __name__ == "__main__":
    scheduler = BackgroundScheduler()
    scheduler.add_job(take_screenshot, trigger="cron", day_of_week=1, hour=0)  # Run the job every Monday at 00:00
    scheduler.start()
    app.run(port=8080)